227	func main() {
228		// Parse command-line flags and get configuration
229		cfg := config.ParseFlags()
230	
231		// Handle --version: print version and exit
232		if cfg.ShowVersion {
233			fmt.Printf("ralph %s\n", config.Version)
234			return
235		}
236	
237		// Handle --show-prompt: print embedded prompt and exit
238		if cfg.ShowPrompt {
239			var showLoader *prompt.Loader
240			if cfg.IsPlanMode() {
241				showLoader = prompt.NewPlanLoader("", cfg.Goal, cfg.PlanFile)
242			} else if cfg.IsAutoresearchMode() {
243				showLoader = prompt.NewAutoresearchLoader("", cfg.Goal, "(experiment content will be loaded at runtime)")
244			} else {
245				showLoader = prompt.NewLoader("", cfg.Goal, cfg.PlanFile)
246			}
247			content, err := showLoader.Load()
248			if err != nil {
249				fmt.Fprintf(os.Stderr, "Error: %v\n", err)
250				os.Exit(1)
251			}
252			fmt.Print(content)
253			return
254		}
255	
256		// Handle autoresearch mode: create template and exit if experiment file doesn't exist
257		if cfg.IsAutoresearchMode() {
258			experimentFile := cfg.AutoresearchFile
259			if experimentFile == "" {
260				experimentFile = "specs/experiment.md"
261			}
262	
263			info, statErr := os.Stat(experimentFile)
264			if os.IsNotExist(statErr) || (statErr == nil && info.Size() == 0) {
265				// Create template
266				templateContent, tmplErr := prompt.GetEmbeddedAutoresearchTemplate()
267				if tmplErr != nil {
268					fmt.Fprintf(os.Stderr, "Error loading template: %v\n", tmplErr)
269					os.Exit(1)
270				}
271				// Ensure specs/ directory exists
272				os.MkdirAll("specs", 0755)
273				templatePath := "specs/autoresearch_template.md"
274				if writeErr := os.WriteFile(templatePath, []byte(templateContent), 0644); writeErr != nil {
275					fmt.Fprintf(os.Stderr, "Error creating template: %v\n", writeErr)
276					os.Exit(1)
277				}
278				fmt.Printf("Created %s\nEdit it with your experiment details, then copy to %s and run `ralph autoresearch` again.\n", templatePath, experimentFile)
279				return
280			} else if statErr != nil {
281				fmt.Fprintf(os.Stderr, "Error checking experiment file: %v\n", statErr)
282				os.Exit(1)
283			}
284		}
285	
286		// Wrap in tmux if not already inside one (skip in CLI mode)
287		if !cfg.CLI && tmux.ShouldWrap(cfg.NoTmux) {
288			if err := tmux.Wrap(cfg.Subcommand); err != nil {
289				fmt.Fprintf(os.Stderr, "Warning: Could not wrap in tmux: %v\n", err)
290				// Continue without tmux
291			}
292		}
293	
294		// Validate configuration
295		if err := cfg.Validate(); err != nil {
296			fmt.Fprintf(os.Stderr, "Error: %v\n", err)
297			os.Exit(1)
298		}
299	
300		// Load the loop prompt (embedded or from override file)
301		var promptLoader *prompt.Loader
302		if cfg.IsAutoresearchMode() {
303			experimentFile := cfg.AutoresearchFile
304			if experimentFile == "" {
305				experimentFile = "specs/experiment.md"
306			}
307			experimentContent, readErr := os.ReadFile(experimentFile)
308			if readErr != nil {
309				fmt.Fprintf(os.Stderr, "Error reading experiment file %s: %v\n", experimentFile, readErr)
310				os.Exit(1)
311			}
312			promptLoader = prompt.NewAutoresearchLoader(cfg.LoopPrompt, cfg.Goal, string(experimentContent))
313		} else if cfg.IsPlanMode() {
314			promptLoader = prompt.NewPlanLoader(cfg.LoopPrompt, cfg.Goal, cfg.PlanFile)
315		} else {
316			promptLoader = prompt.NewLoader(cfg.LoopPrompt, cfg.Goal, cfg.PlanFile)
317		}
318		promptContent, err := promptLoader.Load()
319		if err != nil {
320			fmt.Fprintf(os.Stderr, "Error loading prompt: %v\n", err)
321			os.Exit(1)
322		}
323	
324		// Load existing stats (if any)
325		tokenStats, err := stats.LoadTokenStats(statsFilePath)
326		if err != nil {
327			fmt.Fprintf(os.Stderr, "Warning: Could not load stats: %v\n", err)
328			tokenStats = stats.NewTokenStats()
329		}
330	
331		// Initialize DB context for stats tracking (best-effort)
332		dbCtx := initDBContext()
333		if dbCtx.db != nil {
334			defer dbCtx.db.Close()
335		}
336	
337		// Open log file (truncated each run); fall back to io.Discard on error
338		var logFile io.Writer
339		logFileHandle, err := os.Create(logFilePath)
340		if err != nil {
341			fmt.Fprintf(os.Stderr, "Warning: Could not open log file %s: %v\n", logFilePath, err)
342			logFile = io.Discard
343		} else {
344			logFile = logFileHandle
345			defer logFileHandle.Close()
346		}
347	
348		// CLI mode: run without TUI, output to stdout/stderr, exit when complete
349		if cfg.CLI {
350			var exitCode int
351			if cfg.IsPlanAndBuildMode() {
352				exitCode = runPlanAndBuildCLI(cfg, tokenStats, logFile, dbCtx)
353			} else {
354				exitCode = runCLI(cfg, promptContent, tokenStats, logFile, dbCtx)
355			}
356			if err := tokenStats.Save(statsFilePath); err != nil {
357				fmt.Fprintf(os.Stderr, "Warning: Could not save stats: %v\n", err)
358			}
359			exportSessionTSV(dbCtx)
360			os.Exit(exitCode)
361		}
362	
363		// Plan-and-build mode: run planning (1 iteration) then building (N iterations) in single TUI session
364		if cfg.IsPlanAndBuildMode() {
365			runPlanAndBuild(cfg, tokenStats, logFile, dbCtx)
366			if err := tokenStats.Save(statsFilePath); err != nil {
367				fmt.Fprintf(os.Stderr, "Warning: Could not save stats: %v\n", err)
368			}
369			exportSessionTSV(dbCtx)
370			return
371		}
372	
373		// Set up channels for TUI communication
374		msgChan := make(chan tui.Message, 100)
375		doneChan := make(chan struct{})
