14		MessageTypeSystem    MessageType = "system"
15		MessageTypeAssistant MessageType = "assistant"
16		MessageTypeUser      MessageType = "user"
17		MessageTypeResult    MessageType = "result"
18		MessageTypeRateLimit MessageType = "rate_limit_event"
19		MessageTypeUnknown   MessageType = "unknown"
20	)
