22	// ContentType represents the type of content within a message
23	type ContentType string
24	
25	const (
26		ContentTypeText       ContentType = "text"
27		ContentTypeToolUse    ContentType = "tool_use"
28		ContentTypeToolResult ContentType = "tool_result"
29		ContentTypeThinking   ContentType = "thinking"
