32	// Usage represents token usage information from Claude
33	type Usage struct {
34		InputTokens              int64 `json:"input_tokens"`
35		OutputTokens             int64 `json:"output_tokens"`
36		CacheCreationInputTokens int64 `json:"cache_creation_input_tokens"`
