40	// RateLimitInfo holds rate limit event data from Claude CLI
41	type RateLimitInfo struct {
42		Status        string `json:"status"`                  // "rejected" means blocked
43		ResetsAt      int64  `json:"resetsAt"`                // Unix timestamp when limit resets
44		RateLimitType string `json:"rateLimitType,omitempty"` // Type of rate limit (e.g., "token")
45	}
