47	// ContentItem represents a single content item in a message
48	type ContentItem struct {
49		Type           ContentType            `json:"type"`
50		Text           string                 `json:"text,omitempty"`
51		ID             string                 `json:"id,omitempty"`          // Tool use ID for tool_use
52		Name           string                 `json:"name,omitempty"`        // Tool name for tool_use
53		Input          map[string]interface{} `json:"input,omitempty"`       // Tool input for tool_use
54		ToolUseID      string                 `json:"tool_use_id,omitempty"` // Tool use ID for tool_result
55		Content        interface{}            `json:"content,omitempty"`     // Tool result content
56		ThinkingText   string                 `json:"thinking,omitempty"`    // Thinking content for thinking items
57	}
