105	// TaskReference represents a detected IMPLEMENTATION_PLAN.md task reference
106	type TaskReference struct {
107		Number      int
108		Description string // Optional description (e.g., "Track IMPLEMENTATION_PLAN.md Phase/Task")
109	}
