111	// Parser handles parsing of Claude's stream-json output
112	type Parser struct {
113		systemReminderRegex *regexp.Regexp
114		loopMarkerRegex     *regexp.Regexp
115		thinkingRegex       *regexp.Regexp
116		taskRegex           *regexp.Regexp
117		taskWithDescRegex   *regexp.Regexp
118	}
119	
120	// NewParser creates a new Parser instance
121	func NewParser() *Parser {
122		return &Parser{
123			systemReminderRegex: regexp.MustCompile(`(?s)<system-reminder>.*?</system-reminder>`),
124			loopMarkerRegex:     regexp.MustCompile(`LOOP (\d+)/(\d+)`),
125			thinkingRegex:       regexp.MustCompile(`(?s)<thinking>(.*?)</thinking>`),
126			taskRegex:           regexp.MustCompile(`(?i)TASK\s+(\d+)`),
127			taskWithDescRegex:   regexp.MustCompile(`(?i)TASK\s+(\d+)\s*:\s*([^\[\n]+)`),
128		}
129	}
