131	// ParseLine parses a single line of Claude output
132	// Returns a ParsedMessage if the line contains valid JSON, nil otherwise
133	func (p *Parser) ParseLine(line string) *ParsedMessage {
134		line = strings.TrimSpace(line)
135	
136		// Skip empty lines and loop markers (they're not JSON)
137		if line == "" || strings.HasPrefix(line, "=======") {
138			return nil
139		}
140	
141		// Skip non-JSON lines
142		if !strings.HasPrefix(line, "{") {
143			return nil
144		}
145	
146		var msg ParsedMessage
147		if err := json.Unmarshal([]byte(line), &msg); err != nil {
148			return nil
149		}
150	
151		msg.RawJSON = line
152		return &msg
153	}
154	
155	// ParseLoopMarker extracts loop marker information from a line
156	// Returns nil if the line is not a loop marker
157	func (p *Parser) ParseLoopMarker(line string) *LoopMarker {
158		line = strings.TrimSpace(line)
159	
160		if !strings.HasPrefix(line, "=======") {
161			return nil
162		}
163	
164		matches := p.loopMarkerRegex.FindStringSubmatch(line)
165		if len(matches) != 3 {
166			return nil
167		}
168	
169		var current, total int
170	
171		// Parse current and total
172		current = parseInt(matches[1])
173		total = parseInt(matches[2])
174	
175		return &LoopMarker{
176			Current: current,
177			Total:   total,
178		}
179	}
