181	// parseInt safely parses an integer from a string, returning 0 on error
182	func parseInt(s string) int {
183		var result int
184		for _, c := range s {
185			if c >= '0' && c <= '9' {
186				result = result*10 + int(c-'0')
187			}
188		}
189		return result
190	}
