192	// StripSystemReminders removes <system-reminder> tags and their content from text
193	func (p *Parser) StripSystemReminders(text string) string {
194		result := p.systemReminderRegex.ReplaceAllString(text, "")
195		return strings.TrimSpace(result)
196	}
197	
198	// ExtractThinking extracts <thinking> content from text
199	// Returns empty string if no thinking block is found
200	func (p *Parser) ExtractThinking(text string) string {
201		matches := p.thinkingRegex.FindStringSubmatch(text)
202		if len(matches) < 2 {
203			return ""
204		}
205		return strings.TrimSpace(matches[1])
206	}
