208	// ExtractContent processes a ParsedMessage and extracts its content
209	func (p *Parser) ExtractContent(msg *ParsedMessage) *ParsedContent {
210		if msg == nil || msg.Message == nil {
211			return &ParsedContent{}
212		}
213	
214		content := &ParsedContent{
215			TextContent: []string{},
216			ToolUses:    []ToolUse{},
217			ToolResults: []ToolResult{},
218		}
219	
220		for _, item := range msg.Message.Content {
221			switch item.Type {
222			case ContentTypeText:
223				text := p.StripSystemReminders(item.Text)
224				if text != "" {
225					// Check for thinking
226					thinking := p.ExtractThinking(text)
227					if thinking != "" {
228						content.Thinking = thinking
229					} else {
230						content.TextContent = append(content.TextContent, text)
231					}
232				}
233	
234			case ContentTypeThinking:
235				if item.ThinkingText != "" {
236					content.Thinking = item.ThinkingText
237				}
238	
239			case ContentTypeToolUse:
240				inputJSON := "{}"
241				if item.Input != nil {
242					if jsonBytes, err := json.MarshalIndent(item.Input, "", "  "); err == nil {
243						inputJSON = string(jsonBytes)
244					}
245				}
246				// Truncate to 150 characters like Python version
247				if len(inputJSON) > 150 {
248					inputJSON = inputJSON[:150]
249				}
250				content.ToolUses = append(content.ToolUses, ToolUse{
251					Name:      item.Name,
252					InputJSON: inputJSON,
253					FilePath:  ExtractFilePathFromInput(item.Input),
254				})
255	
256			case ContentTypeToolResult:
257				resultText := ""
258				switch v := item.Content.(type) {
259				case string:
260					resultText = v
261				case map[string]interface{}:
262					if jsonBytes, err := json.Marshal(v); err == nil {
263						resultText = string(jsonBytes)
264					}
265				}
266				resultText = p.StripSystemReminders(resultText)
267				if resultText != "" {
268					content.ToolResults = append(content.ToolResults, ToolResult{
269						Content: resultText,
270					})
271				}
272			}
273		}
274	
275		return content
276	}
