315	// IsRateLimitRejected checks if message is a rate limit rejection.
316	// Returns (true, resetTime) if rejected, (false, zero) otherwise.
317	// Handles two patterns:
318	// - Pattern 1: type: "rate_limit_event" with rate_limit_info.status == "rejected"
319	// - Pattern 2: is_error: true with error: "rate_limit"
320	func (p *Parser) IsRateLimitRejected(msg *ParsedMessage) (bool, time.Time) {
321		if msg == nil || msg.RateLimitInfo == nil {
322			return false, time.Time{}
323		}
324		if msg.RateLimitInfo.Status != "rejected" {
325			return false, time.Time{}
326		}
327		return true, time.Unix(msg.RateLimitInfo.ResetsAt, 0)
328	}
