330	// IsAPIOverloaded checks if message indicates an API 529 (overloaded) error.
331	// Returns true if the message has is_error set and the error string contains
332	// "529" or "overloaded" (case-insensitive).
333	func (p *Parser) IsAPIOverloaded(msg *ParsedMessage) bool {
334		if msg == nil || !msg.IsError {
335			return false
336		}
337		errLower := strings.ToLower(msg.Error)
338		return strings.Contains(errLower, "529") || strings.Contains(errLower, "overloaded")
339	}
340	
341	// IsAuthenticationError checks if message indicates an authentication error.
342	// Returns true if the error string contains auth-related keywords.
343	// Checks both is_error messages (result type) and assistant messages where
344	// the error field is set without is_error (e.g. "authentication_failed").
345	func (p *Parser) IsAuthenticationError(msg *ParsedMessage) bool {
346		if msg == nil || msg.Error == "" {
347			return false
348		}
349		errLower := strings.ToLower(msg.Error)
350		return strings.Contains(errLower, "authentication") ||
351			strings.Contains(errLower, "unauthorized") ||
352			strings.Contains(errLower, "invalid_api_key") ||
353			strings.Contains(errLower, "login")
354	}
