356	// IsSubagentMessage returns true if the message originates from a subagent
357	// (i.e., has a non-nil, non-empty parent_tool_use_id)
358	func (p *Parser) IsSubagentMessage(msg *ParsedMessage) bool {
359		if msg == nil || msg.ParentToolUseID == nil {
360			return false
361		}
362		return *msg.ParentToolUseID != ""
363	}
