365	// GetTaskToolUseIDs returns the IDs of any "Task" tool_use content items in the message.
366	// These IDs correspond to subagents being spawned.
367	func (p *Parser) GetTaskToolUseIDs(msg *ParsedMessage) []string {
368		if msg == nil || msg.Message == nil {
369			return nil
370		}
371		var ids []string
372		for _, item := range msg.Message.Content {
373			if item.Type == ContentTypeToolUse && item.Name == "Task" && item.ID != "" {
374				ids = append(ids, item.ID)
375			}
376		}
377		return ids
378	}
