380	// ExtractFilePathFromInput extracts a file path or pattern from a tool input map.
381	// Returns the first match from: file_path, path, pattern, command (truncated), description.
382	// Returns empty string if no relevant field is found.
383	func ExtractFilePathFromInput(input map[string]interface{}) string {
384		// Try file_path first (Read, Write, Edit)
385		if path, ok := input["file_path"].(string); ok && path != "" {
386			return path
387		}
388		// Try path (some tools use this)
389		if path, ok := input["path"].(string); ok && path != "" {
390			return path
391		}
392		// Try pattern (Glob, Grep)
393		if pattern, ok := input["pattern"].(string); ok && pattern != "" {
394			return pattern
395		}
396		// Try command (Bash) - truncate to first 50 chars
397		if cmd, ok := input["command"].(string); ok && cmd != "" {
398			if len(cmd) > 50 {
399				return cmd[:50] + "..."
400			}
401			return cmd
402		}
403		// Try description (Task)
404		if desc, ok := input["description"].(string); ok && desc != "" {
405			return desc
406		}
407		return ""
408	}
