410	// ExtractTaskReference scans text for references to IMPLEMENTATION_PLAN.md tasks
411	// (e.g., "TASK 6", "Task 3: Some Description"). Returns the last match found,
412	// or nil if no task reference is detected.
413	func (p *Parser) ExtractTaskReference(text string) *TaskReference {
414		// Try the more specific pattern first (TASK N: description)
415		descMatches := p.taskWithDescRegex.FindAllStringSubmatch(text, -1)
416		if len(descMatches) > 0 {
417			last := descMatches[len(descMatches)-1]
418			num := parseInt(last[1])
419			if num > 0 {
420				return &TaskReference{
421					Number:      num,
422					Description: strings.TrimSpace(last[2]),
423				}
424			}
425		}
426	
427		// Fall back to simple pattern (TASK N)
428		matches := p.taskRegex.FindAllStringSubmatch(text, -1)
429		if len(matches) > 0 {
430			last := matches[len(matches)-1]
431			num := parseInt(last[1])
432			if num > 0 {
433				return &TaskReference{
434					Number: num,
435				}
436			}
437		}
438	
439		return nil
440	}
